module counter_4bit (obf_clk, rst, en, count);
   input obf_clk, rst, en;
   output [3:0] count;

   reg [3:0] count;

always @(posedge obf_clk or posedge rst) begin
    if (rst) 
    begin
        count <= 0;
    end 
    else if (en) 
    begin
        count <= count + 1;
    end
end

endmodule
